`timescale 1ns / 1ps
//=============================================================================
// mlp_classifier_pipelined.v
// Multi-Threat Acoustic Classifier — 4-Stage Pipelined MLP Inference Engine
//
// Architecture : 16 inputs → 32 hidden (ReLU) → 16 hidden (ReLU) → 3 outputs
// Matches Python: MLPClassifier(hidden_layer_sizes=(32,16), activation='relu')
//
// Fixed-point  : Q8 format — all weights and inputs scaled by 256
// Pipeline     : Stage 1 → Layer 1 MAC       (16 inputs  → 32 neurons)
//                Stage 2 → ReLU1 + Layer 2 MAC (32 neurons → 16 neurons)
//                Stage 3 → ReLU2 + Layer 3 MAC (16 neurons →  3 outputs)
//                Stage 4 → Argmax + conf_delta + threat flag
// Latency      : 4 clock cycles
// Throughput   : 1 classification / cycle (after pipeline fill)
// Classes      : 00 = Background | 01 = Gunshot | 10 = Drone
//
// WEIGHT PLACEHOLDERS: All localparams are 0.
// Run build_dataset.py → train_evaluate.py → export_verilog_weights.py
// then replace these blocks with the generated output.
//=============================================================================
module mlp_classifier_pipelined (
    input  wire        clk,
    input  wire        rst,
    input  wire        valid_in,

    input  wire signed [15:0] x0,   // MFCC 1
    input  wire signed [15:0] x1,   // MFCC 2
    input  wire signed [15:0] x2,   // MFCC 3
    input  wire signed [15:0] x3,   // MFCC 4
    input  wire signed [15:0] x4,   // MFCC 5
    input  wire signed [15:0] x5,   // MFCC 6
    input  wire signed [15:0] x6,   // MFCC 7
    input  wire signed [15:0] x7,   // MFCC 8
    input  wire signed [15:0] x8,   // MFCC 9
    input  wire signed [15:0] x9,   // MFCC 10
    input  wire signed [15:0] x10,  // Spectral Centroid
    input  wire signed [15:0] x11,  // Spectral Rolloff
    input  wire signed [15:0] x12,  // Zero Crossing Rate
    input  wire signed [15:0] x13,  // Band Energy Low  (0-500 Hz)
    input  wire signed [15:0] x14,  // Band Energy Mid  (500-2000 Hz)
    input  wire signed [15:0] x15,  // Band Energy High (2000-8000 Hz)

    output reg  [1:0]         class_out,
    output reg                valid_out,
    output reg  signed [31:0] conf_delta,
    output reg                threat
);

