            s2_net[11] <= ((h1[0]*W2_0_11+h1[1]*W2_1_11+h1[2]*W2_2_11+h1[3]*W2_3_11+h1[4]*W2_4_11+h1[5]*W2_5_11+h1[6]*W2_6_11+h1[7]*W2_7_11+h1[8]*W2_8_11+h1[9]*W2_9_11+h1[10]*W2_10_11+h1[11]*W2_11_11+h1[12]*W2_12_11+h1[13]*W2_13_11+h1[14]*W2_14_11+h1[15]*W2_15_11+h1[16]*W2_16_11+h1[17]*W2_17_11+h1[18]*W2_18_11+h1[19]*W2_19_11+h1[20]*W2_20_11+h1[21]*W2_21_11+h1[22]*W2_22_11+h1[23]*W2_23_11+h1[24]*W2_24_11+h1[25]*W2_25_11+h1[26]*W2_26_11+h1[27]*W2_27_11+h1[28]*W2_28_11+h1[29]*W2_29_11+h1[30]*W2_30_11+h1[31]*W2_31_11)>>>8)+B2_11;
