//=============================================================================
// STAGE 3: ReLU2 (combinational) + Layer 3 MAC — 16 → 3
//=============================================================================
wire signed [31:0] h2 [0:15];
genvar g2;
generate for (g2=0; g2<16; g2=g2+1) begin : relu2
    assign h2[g2] = s2_net[g2] > 0 ? s2_net[g2] : 32'sd0;
end endgenerate

always @(posedge clk or posedge rst) begin
    if (rst) begin
        s3_out[0] <= 0; s3_out[1] <= 0; s3_out[2] <= 0;
        s3_valid  <= 0;
    end else begin
        s3_valid <= s2_valid;
        if (s2_valid) begin
            s3_out[0] <= ((h2[0]*W3_0_0+h2[1]*W3_1_0+h2[2]*W3_2_0+h2[3]*W3_3_0+h2[4]*W3_4_0+h2[5]*W3_5_0+h2[6]*W3_6_0+h2[7]*W3_7_0+h2[8]*W3_8_0+h2[9]*W3_9_0+h2[10]*W3_10_0+h2[11]*W3_11_0+h2[12]*W3_12_0+h2[13]*W3_13_0+h2[14]*W3_14_0+h2[15]*W3_15_0)>>>8)+B3_0;
            s3_out[1] <= ((h2[0]*W3_0_1+h2[1]*W3_1_1+h2[2]*W3_2_1+h2[3]*W3_3_1+h2[4]*W3_4_1+h2[5]*W3_5_1+h2[6]*W3_6_1+h2[7]*W3_7_1+h2[8]*W3_8_1+h2[9]*W3_9_1+h2[10]*W3_10_1+h2[11]*W3_11_1+h2[12]*W3_12_1+h2[13]*W3_13_1+h2[14]*W3_14_1+h2[15]*W3_15_1)>>>8)+B3_1;
            s3_out[2] <= ((h2[0]*W3_0_2+h2[1]*W3_1_2+h2[2]*W3_2_2+h2[3]*W3_3_2+h2[4]*W3_4_2+h2[5]*W3_5_2+h2[6]*W3_6_2+h2[7]*W3_7_2+h2[8]*W3_8_2+h2[9]*W3_9_2+h2[10]*W3_10_2+h2[11]*W3_11_2+h2[12]*W3_12_2+h2[13]*W3_13_2+h2[14]*W3_14_2+h2[15]*W3_15_2)>>>8)+B3_2;
        end
    end
end

//=============================================================================
// STAGE 4: Argmax + Confidence Delta + Threat Flag
//=============================================================================
wire signed [31:0] max_score, second_score;
wire [1:0] winner;

localparam signed [31:0] CONF_THRESHOLD = 500;

assign winner = (s3_out[0]>=s3_out[1] && s3_out[0]>=s3_out[2]) ? 2'b00 :
                (s3_out[1]>=s3_out[0] && s3_out[1]>=s3_out[2]) ? 2'b01 :
                                                                   2'b10;
assign max_score    = (winner==2'b00) ? s3_out[0] : (winner==2'b01) ? s3_out[1] : s3_out[2];
wire signed [31:0] other_a = (winner==2'b00) ? s3_out[1] : s3_out[0];
wire signed [31:0] other_b = (winner==2'b10) ? s3_out[1] : s3_out[2];
assign second_score = (other_a >= other_b) ? other_a : other_b;

always @(posedge clk or posedge rst) begin
    if (rst) begin
        class_out <= 2'b00; valid_out <= 0; conf_delta <= 0; threat <= 0;
    end else begin
        valid_out <= s3_valid;
        if (s3_valid) begin
            class_out  <= winner;
            conf_delta <= max_score - second_score;
            // Only assert threat if class is not Background and confidence > threshold
            threat     <= (winner != 2'b00) && ((max_score - second_score) > CONF_THRESHOLD);
        end
    end
end

endmodule